- Example
```
// t_inside_unbound.v
module t;
    initial begin
        int value;

        // Test [$:5] - should match minimum to 5
        value = 3;
        if (!(value inside {[$:5]})) $stop;

        // Test [5:$] - should match 5 to maximum
        value = 10;
        if (!(value inside {[5:$]})) $stop;

        // Negative test
        value = 3;
        if (value inside {[5:$]}) $stop;

        $write("*-* All Finished *-*\n");
        $finish;
    end
endmodule
```

